import { requireAuth } from '@/lib/supabase/server';
import { createClient } from '@/lib/supabase/server';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Database, Table, HardDrive, Activity } from 'lucide-react';
import { Badge } from '@/components/ui/badge';

export default async function AdminDatabasePage() {
    const profile = await requireAuth();
    const supabase = await createClient();

    // Fetch table counts
    const tables = [
        { name: 'profiles', label: 'Perfis' },
        { name: 'organizations', label: 'Organizações' },
        { name: 'crm_contacts', label: 'Contatos' },
        { name: 'crm_deals', label: 'Deals' },
        { name: 'medical_appointments', label: 'Consultas' },
        { name: 'medical_records', label: 'Prontuários' },
        { name: 'financial_transactions', label: 'Transações' },
        { name: 'financial_accounts', label: 'Contas' },
        { name: 'whatsapp_conversations', label: 'Conversas WhatsApp' },
        { name: 'whatsapp_messages', label: 'Mensagens WhatsApp' },
    ];

    const tableCounts = await Promise.all(
        tables.map(async (table) => {
            const { count } = await supabase
                .from(table.name as any)
                .select('*', { count: 'exact', head: true });
            return { ...table, count: count || 0 };
        })
    );

    const totalRecords = tableCounts.reduce((sum, t) => sum + t.count, 0);

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-2xl font-bold">Visão do Banco de Dados</h1>
                <p className="text-muted-foreground">Estatísticas e informações do banco de dados</p>
            </div>

            {/* Overview Cards */}
            <div className="grid gap-4 md:grid-cols-4">
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Total de Registros</CardTitle>
                        <Database className="h-4 w-4 text-blue-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{totalRecords.toLocaleString('pt-BR')}</div>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Tabelas Monitoradas</CardTitle>
                        <Table className="h-4 w-4 text-purple-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{tables.length}</div>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Provedor</CardTitle>
                        <HardDrive className="h-4 w-4 text-green-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">Supabase</div>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Status</CardTitle>
                        <Activity className="h-4 w-4 text-green-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-green-500">Online</div>
                    </CardContent>
                </Card>
            </div>

            {/* Tables Grid */}
            <Card>
                <CardHeader>
                    <CardTitle>Estatísticas por Tabela</CardTitle>
                    <CardDescription>Contagem de registros em cada tabela principal</CardDescription>
                </CardHeader>
                <CardContent>
                    <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                        {tableCounts.map((table) => (
                            <div
                                key={table.name}
                                className="flex items-center justify-between p-4 border rounded-lg"
                            >
                                <div>
                                    <p className="font-medium">{table.label}</p>
                                    <p className="text-xs text-muted-foreground">{table.name}</p>
                                </div>
                                <Badge variant="secondary" className="text-lg px-3 py-1">
                                    {table.count.toLocaleString('pt-BR')}
                                </Badge>
                            </div>
                        ))}
                    </div>
                </CardContent>
            </Card>
        </div>
    );
}
